import json, re
# Get businesses and reviews
businesses = locals()['var_functions.query_db:34']
reviews = locals()['var_functions.query_db:18']

# Extract categories from each business description
categories_map = {}
for biz in businesses:
    desc = biz['description']
    # Try to extract category phrases
    # Pattern 1: comma-separated list after "including" or similar
    # Pattern 2: final phrase after "of" 
    # Pattern 3: explicit category list in quotes
    cats = []

    text = desc.lower()

    # Extract phrases after "including" or "in" patterns
    if 'including' in text:
        # Get text after "including"
        after = text.split('including', 1)[1].strip()
        # Stop at period if present
        if '.' in after:
            after = after.split('.')[0]
        # Extract comma-separated phrases
        parts = re.split(r',|\band\b', after)
        for part in parts:
            part = part.strip()
            if part and len(part) > 2:
                cats.append(part.strip().title())

    # Also try to find explicit category list in quotes
    if "'" in desc and (',' in desc or ' and ' in desc):
        # Manual extraction for Chinese restaurants
        if 'chinese' in text:
            cats.append('Restaurants')
            cats.append('Chinese')

        # For multi-service businesses like Luminosity
        if 'cosmetics & beauty supply' in text:
            cats.extend(['Cosmetics & Beauty Supply', 'Beauty & Spas'])
        if 'dentists' in text:
            cats.append('Dentists')

    # Add a main category based on patterns
    main_cat = None
    if 'restaurant' in text or 'cafe' in text or 'diner' in text:
        main_cat = 'Restaurants'
    elif 'salon' in text or 'spa' in text or 'beauty' in text:
        main_cat = 'Beauty & Spas'
    elif 'doctor' in text or 'medicine' in text or 'health' in text:
        main_cat = 'Health & Medical'
    elif 'school' in text or 'education' in text:
        main_cat = 'Education'
    elif 'store' in text or 'shop' in text:
        main_cat = 'Shopping'
    elif 'bar' in text or 'night' in text:
        main_cat = 'Nightlife'

    if main_cat and main_cat not in cats:
        cats.append(main_cat)

    # Default to uncategorized if no categories found
    if not cats:
        cats = ['Uncategorized']

    categories_map[biz['business_id']] = cats

print('Categories extracted for', len(categories_map), 'businesses')
print('Sample mappings:')
for k, v in list(categories_map.items())[:5]:
    print(k, '->', v)

# Count reviews per category
category_counts = {}
# Create business_ref to business_id mapping
business_ref_map = {k.replace('businessid_', 'businessref_'): k for k in categories_map.keys()}

for review in reviews:
    biz_ref = review['business_ref']
    biz_id = business_ref_map.get(biz_ref)
    if biz_id and biz_id in categories_map:
        for cat in categories_map[biz_id]:
            category_counts[cat] = category_counts.get(cat, 0) + 1
    else:
        # If business not found, count as uncategorized
        category_counts['Uncategorized'] = category_counts.get('Uncategorized', 0) + 1

# Sort by count descending
sorted_cats = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)
print('Top categories:')
for cat, count in sorted_cats:
    print(f"{cat}: {count}")

print('__RESULT__:')
print(json.dumps(sorted_cats))

