businesses = locals()['var_functions.query_db:34']
reviews = locals()['var_functions.query_db:18']

# Manually parse categories from descriptions
categories_map = {}

# We'll use pattern matching on each description
for biz in businesses:
    desc = biz['description']
    biz_id = biz['business_id']
    cats = []

    # Pattern: services in X, Y, Z
    if 'services in' in desc:
        after = desc.split('services in', 1)[1].strip()
        # Remove location/address info
        if ' in ' in after:
            after = after.rsplit(' in ', 1)[0]
        if '.' in after:
            after = after.split('.')[0]
        # Extract comma-separated categories
        for part in after.split(','):
            part = part.strip()
            # Remove trailing conjunctions
            if ' and ' in part:
                part = part.split(' and ')[0].strip()
            if part and len(part) > 2:
                # Normalize
                if part.startswith("'"):
                    part = part.strip("'")
                if ' doctors' == part.lower():
                    part = "Doctors"
                elif 'health & medical' in part.lower():
                    part = "Health & Medical"
                cats.append(part.strip())

    # Pattern: services including X, Y, Z
    if not cats and 'including' in desc:
        after = desc.split('including', 1)[1].strip()
        if '.' in after:
            after = after.split('.')[0]
        for part in after.split(','):
            part = part.strip()
            if ' and ' in part:
                part = part.split(' and ')[0].strip()
            if part and len(part) > 2:
                # Skip generic words
                if part.lower() not in ['food', 'a', 'an', 'the', 'and', 'or']:
                    if part.startswith("'"):
                        part = part.strip("'")
                    cats.append(part.strip())

    # Pattern: seeking X, Y, Z
    if not cats and 'seeking' in desc:
        after = desc.split('seeking', 1)[1].strip()
        if '.' in after:
            after = after.split('.')[0]
        for part in after.split(','):
            part = part.strip()
            if ' and ' in part:
                part = part.split(' and ')[0].strip()
            if part and len(part) > 2:
                cats.append(part.strip())

    # Manual overrides for specific well-known categories
    if biz_id == 'businessid_41':
        cats = ['Internal Medicine', 'Doctors', 'Health & Medical']
    elif biz_id == 'businessid_33':
        cats = ['Nail Salons', 'Hair Removal', 'Beauty & Spas', 'Waxing']
    elif biz_id == 'businessid_74':
        cats = ['Candy Stores', 'Specialty Food', 'Food']
    elif biz_id == 'businessid_92':
        cats = ['Cosmetics & Beauty Supply', 'Cosmetic Dentists', 'Tanning', 'Teeth Whitening', 
                'Beauty & Spas', 'Dentists', 'Shopping', 'Blow Dry/Out Services', 'Health & Medical', 
                'Spray Tanning', 'Hair Salons']
    elif biz_id == 'businessid_10':
        cats = ['Restaurants', 'Chinese']

    categories_map[biz_id] = cats

print('Mapped categories for:', len(categories_map), 'businesses')
for k,v in categories_map.items():
    print(k, '->', v)

# Count reviews per category
business_ref_map = {k.replace('businessid_', 'businessref_'): k for k in categories_map.keys()}

# Actually we need to query the FULL set of businesses that were reviewed by 2016 users
# We only have 5 businesses loaded currently. Let's re-query with all business IDs.
print('__RESULT__:')
print(json.dumps(list(categories_map.items())))

